import{_ as a}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as o,o as i,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"es/getting-started/dashboard.md","filePath":"es/getting-started/dashboard.md"}'),l={name:"es/getting-started/dashboard.md"};function n(s,e,d,c,u,m){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; Dashboard&quot;">​</a></h1><p>El <strong>Dashboard</strong> es un potente panel de control y analizador de rendimiento integrado en el juego. Te permite monitorear el funcionamiento del plugin, analizar los tiempos de los fotogramas, y anular manualmente los niveles de los Scalers directamente en una build en ejecución.</p><p><img src="'+a+'" alt=""></p><h2 id="como-usarlo" tabindex="-1">Cómo Usarlo <a class="header-anchor" href="#como-usarlo" aria-label="Permalink to &quot;Cómo Usarlo&quot;">​</a></h2><p>Arrastra y suelta el <code>Dashboard.prefab</code> en cualquier escena de tu proyecto.<br> Se configurará automáticamente como <code>DontDestroyOnLoad</code> y permanecerá disponible durante las transiciones de escena.</p><div class="info custom-block"><p class="custom-block-title">Notas para Build de Producción</p><p>El Dashboard está completamente desacoplado del núcleo del plugin. Antes de lanzar tu juego, simplemente elimina el prefab de la escena. El sistema de Code Stripping de Unity eliminará automáticamente todo el código del Dashboard de la build final (evitando inflar la carpeta <code>Resources</code>), manteniendo un peso mínimo del proyecto. El núcleo WebAP continuará ejecutándose de fondo.</p></div><h2 id="panel-izquierdo-controles" tabindex="-1"><i class="ph ph-sliders"></i> Panel Izquierdo (Controles) <a class="header-anchor" href="#panel-izquierdo-controles" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Panel Izquierdo (Controles)&quot;">​</a></h2><p>El lado izquierdo del Dashboard está diseñado para la interacción en tiempo real con el plugin.</p><ul><li><strong>Enable Web AP</strong><br> El interruptor global del núcleo del plugin. Si se desactiva, la optimización automática se detiene y todos los parámetros gráficos vuelven a sus valores originales (máximos).</li><li><strong>Anti Yo-Yo Protection</strong><br> Activa o desactiva el Penalty Lockout. Si se desactiva, el plugin puede aumentar y disminuir la calidad gráfica sin bloqueos temporales.<br><em>(Ver detalles: <a href="./../advanced/anti-yoyo">Sistema Anti Yo-Yo</a>)</em></li><li><strong>Active Scalers</strong><br> Una lista de todos los módulos de optimización agregados al sistema. <ul><li><strong>Toggle (Interruptor):</strong> Activa o desactiva dinámicamente un Scaler específico por completo.</li><li><strong>Slider (Deslizador):</strong> Anula manualmente el nivel de calidad (<code>Override Level</code>). Un valor de <code>0</code> significa máxima calidad. Si mueves el deslizador, el Indexer dejará de gestionar este Scaler, permitiéndote evaluar visualmente su impacto en el juego.</li><li><strong>Resolution Mode (Modo de Resolución):</strong> Un ajuste exclusivo del <code>Resolution Scaler</code> (en modo BiRP). Permite cambiar dinámicamente entre las estrategias <code>NativeBrowserScaling</code> y <code>RenderTextureScaling</code>.<br><em>(Ver detalles: <a href="./../scalers/reference">Referencia de Scalers</a>)</em></li></ul></li></ul><h2 id="panel-derecho-analytics" tabindex="-1"><i class="ph ph-chart-bar"></i> Panel Derecho (Analytics) <a class="header-anchor" href="#panel-derecho-analytics" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; Panel Derecho (Analytics)&quot;">​</a></h2><p>El lado derecho muestra las métricas en bruto del motor y la lógica interna del &quot;cerebro&quot; del plugin. Se utilizan algoritmos Zero-GC de Media Móvil Exponencial (Exponential Moving Average) para suavizar los gráficos.</p><h3 id="metricas-y-tiempos-metrics-timings" tabindex="-1">Métricas y Tiempos (Metrics &amp; Timings) <a class="header-anchor" href="#metricas-y-tiempos-metrics-timings" aria-label="Permalink to &quot;Métricas y Tiempos (Metrics &amp; Timings)&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> El objetivo de rendimiento de referencia recuperado de la configuración de tu proyecto.</li><li><strong>Current FPS:</strong> La velocidad de fotogramas actual con un gráfico histórico de picos.</li><li><strong>Current Scale / DPI:</strong> El multiplicador de resolución actual. <code>1.00</code> dicta la resolución nativa. Los valores más bajos (e.g., <code>0.50</code>) denotan que el mundo 3D ha reducido su resolución para ahorrar GPU.</li><li><strong>Frame Time / CPU Time:</strong> Tiempos de hardware exactos recopilados a través de <code>FrameTimingManager</code>. Ayudan a comprender cuánto tiempo real invierte la CPU en la lógica del fotograma.</li></ul><h3 id="cerebro-del-plugin-plugin-brain" tabindex="-1">Cerebro del Plugin (Plugin Brain) <a class="header-anchor" href="#cerebro-del-plugin-plugin-brain" aria-label="Permalink to &quot;Cerebro del Plugin (Plugin Brain)&quot;">​</a></h3><p>Muestra la lógica del pipeline de decisiones.<br><em>(Ver detalles: <a href="./../advanced/how-it-works">Cómo Funciona</a>)</em></p><ul><li><strong>Bottleneck:</strong> Identifica qué subsistema del dispositivo está causando el retraso en este momento (<code>CPU</code>, <code>GPU</code>, <code>TargetFrameRate</code>, o <code>Unknown</code>).</li><li><strong>Action:</strong> Indica qué pretende hacer el Indexer (<code>IncreaseQuality</code>, <code>DecreaseQuality</code>, o <code>Stale</code> — si no es necesaria ninguna acción).</li><li><strong>Status (debajo de la Acción):</strong> El estado del sistema: <code>Monitoring...</code> (evaluando fotogramas), <code>Cooldown</code> (esperando estabilidad tras un cambio gráfico), o <code>Penalty Lockout</code> (la penalización Anti Yo-Yo está activa).</li></ul><h3 id="activo-active" tabindex="-1">Activo (Active) <a class="header-anchor" href="#activo-active" aria-label="Permalink to &quot;Activo (Active)&quot;">​</a></h3><ul><li>Una lista de Scalers cuyo nivel está siendo <strong>reducido</strong> actualmente por el sistema para conservar el rendimiento. Si los FPS son altos y todo es óptimo, mostrará <code>- None</code>.</li></ul>',18)])])}const b=o(l,[["render",n]]);export{h as __pageData,b as default};
